class Solution {
public:
    string reformatNumber(string number) {
        string res;
        for (char c : number) {
            if (c != ' ' && c != '-') res += c;
        }
        int n = res.size();
        while (n > 4) {
            res.insert(res.size() - 4, "-");
            n -= 3;
        }
        if (n == 4) res.insert(res.size() - 4, "-");
        return res;
    }
};
```

